    58→    public static double TryGetDouble(IniFile ini, string section, string key, double defaultValue = 0.0)
    59→    {
    60→        string valueStr = ini.ReadValue(section, key);
    61→
    62→        if (string.IsNullOrWhiteSpace(valueStr))
    63→        {
    64→            // 값이 없으면 기본값 0 저장
    65→            ini.WriteValue(section, key, "0");
    66→            return 0.0;
    67→        }
    68→
    69→        if (double.TryParse(valueStr, out double result))
    70→        {
    71→            return result;
    72→        }
    73→
    74→        // 숫자 변환 실패 시도 → 0으로 저장
    75→        //Console.WriteLine($"[INI 경고] {section}:{key} = '{valueStr}' → 숫자 변환 실패, 기본값 0 저장");
    76→        ini.WriteValue(section, key, "0");
    77→        return 0.0;
    78→    }
    79→    public static int TryGetInt(IniFile ini, string section, string key, int defaultValue = 0)
    80→    {
    81→        string valueStr = ini.ReadValue(section, key);
