    96→        ini.WriteValue(section, key, defaultValue.ToString());
    97→        return defaultValue;
    98→    }
    99→    public static void LoadSettingsFromIni()
   100→    {
   101→        IniFile ini = new IniFile("config.ini");
   102→
   103→        // 유틸 함수 정의
   104→        int ReadInt(string section, string key, int defaultValue = 0)
   105→        {
   106→            string val = ini.ReadValue(section, key);
   107→            return int.TryParse(val, out int result) ? result : defaultValue;
   108→        }
   109→
   110→        double ReadDouble(string section, string key, double defaultValue = 0)
   111→        {
   112→            string val = ini.ReadValue(section, key);
   113→            return double.TryParse(val, out double result) ? result : defaultValue;
   114→        }
   115→
   116→        string ReadStr(string section, string key, string defaultValue)
   117→        {
   118→            string val = ini.ReadValue(section, key)?.Trim();
   119→            return string.IsNullOrWhiteSpace(val) ? defaultValue : val;
   120→        }
   121→
   122→        // 공통 시스템 설정
   123→        strPassWord = ReadStr("System", "PassWord", "0");
