     7→namespace NoiseTest
     8→{
     9→    /// <summary>
    10→    /// LS PLC (XGT ASCII) IO 드라이버 안정판 (IN/OUT 64점)
    11→    /// - ReadLoop(수신 스레드) + 누적버퍼 + ETX 프레임 처리
    12→    /// - 상태머신으로 IN 읽기 → OUT 쓰기
    13→    /// - 타임아웃 복구 / 포트 재오픈 / 안전 로깅
    14→    /// - 출력 신뢰성 패치: 락/스냅샷/커밋 + 버전 관리
    15→    /// </summary>
    16→    public sealed class LsPlcIoFast : IDisposable
    17→    {
    18→        // ===== 설정 =====
    19→        public int BaudRate { get; }
    20→        public int PollDelayMs { get; set; } = 10;          // 워커 루프 주기
    21→        public int ResponseTimeoutMs { get; set; } = 1000;  // 응답 타임아웃
    22→        public int ReopenOnTimeoutCount { get; set; } = 3;  // 연속 타임아웃 N회 → 재오픈
    23→        public bool EnableLog { get; set; } = true;
    24→        public bool VerboseTxRx { get; set; } = false;
    25→        public Action<string> Log { get; set; }
    26→
    27→        // 주소
    28→        private const string ADR_IN0 = "%DW4000";
    29→        private const string ADR_IN1 = "%DW4032";
    30→        private const string ADR_OUT0 = "%DW5000";
    31→        private const string ADR_OUT1 = "%DW5032";
    32→        private const string CNT_32 = "20"; // 32 word
    33→
    34→        // 내부 상태
    35→        private readonly SerialPort _port;
    36→        private Thread _rxThread;
    37→        private Thread _workThread;
    38→        private volatile bool _running;
    39→
    40→        private readonly object _rxLock = new object();
    41→        private byte[] _rxAccum = new byte[8192];
    42→        private int _rxAccumLen = 0;
    43→
    44→        private readonly object _txLock = new object();
    45→        private readonly object _outLock = new object(); // 출력 배열 보호 락
    46→
    47→        private readonly bool[] _in = new bool[64];
    48→        private readonly bool[] _out = new bool[64];
    49→        private volatile bool _outDirty = false;
    50→
    51→        // ★ 출력 변경 버전 관리 (출력 유실 방지용)
    52→        private int _outVersion = 0;          // Commit 호출 시 증가하는 버전
    53→        private int _writeCycleVersion = 0;   // 현재 송신 사이클에서 사용 중인 버전
    54→
    55→        private static readonly byte ENQ = 0x05;
    56→        private static readonly byte EOT = 0x04;
    57→        private static readonly byte ETX = 0x03;
    58→
    59→        private readonly Stopwatch _awaitSw = new Stopwatch();
    60→        private int _consecutiveTimeouts = 0;
    61→        private volatile bool _waiting = false;
