   367→        // ===== 수신 스레드 =====
   368→        private void ReadLoop()
   369→        {
   370→            var buf = new byte[2048];
   371→
   372→            while (_running)
   373→            {
   374→                try
   375→                {
   376→                    int n = _port.BaseStream.Read(buf, 0, buf.Length); // blocking
   377→
   378→                    if (n > 0)
   379→                    {
   380→                        AppendRx(buf, n);
   381→                        ProcessFrames();
   382→                    }
   383→                }
   384→                catch (TimeoutException)
   385→                {
   386→                    // ignore
   387→                }
   388→                catch (Exception ex)
   389→                {
   390→                    LogInfo("[ERR] Read: " + ex.Message);
   391→                    Thread.Sleep(10);
   392→                }
   393→            }
   394→        }
