   499→        // ===== 파서 =====
   500→        // 고정 오프셋(11) 시도 → 부족하면 끝쪽에서 128자리(32*4) 숫자 블록 추출
   501→        private bool TryParseInputs(string frame, int dstOffset)
   502→        {
   503→            int ok = 0;
   504→
   505→            // 1) 고정 오프셋(과거 동작과 동일)
   506→            for (int i = 0; i < 32; i++)
   507→            {
   508→                int pos = 11 + i * 4;
   509→                if (pos + 4 > frame.Length)
   510→                {
   511→                    break;
   512→                }
   513→
   514→                int val;
   515→                if (int.TryParse(frame.Substring(pos, 4), out val))
   516→                {
   517→                    _in[dstOffset + i] = (val != 0);
   518→                    ok++;
   519→                }
   520→                else
   521→                {
   522→                    break;
   523→                }
   524→            }
   525→
   526→            if (ok >= 28)
   527→            {
   528→                return true; // 대부분 맞으면 통과
   529→            }
   530→
   531→            // 2) 후방 탐색: 끝에서부터 숫자 연속 구간 중 128자리 이상 찾기
   532→            int tailStart = FindTailDigitRun(frame, 128);
   533→            if (tailStart >= 0)
   534→            {
   535→                int parsed = 0;
   536→                int end = frame.Length;
   537→
   538→                for (int i = 0; i < 32; i++)
   539→                {
   540→                    int s = end - 4 * (32 - i);
   541→                    if (s < tailStart)
   542→                    {
   543→                        break;
   544→                    }
   545→
   546→                    int v;
   547→                    if (int.TryParse(frame.Substring(s, 4), out v))
   548→                    {
   549→                        _in[dstOffset + i] = (v != 0);
   550→                        parsed++;
   551→                    }
   552→                }
   553→
   554→                return parsed == 32;
   555→            }
   556→
   557→            return false;
   558→        }
   559→
   560→        private static int FindTailDigitRun(string s, int minLen)
   561→        {
   562→            int run = 0;
   563→
   564→            for (int i = s.Length - 1; i >= 0; i--)
   565→            {
   566→                if (char.IsDigit(s[i]))
   567→                {
   568→                    run++;
   569→                }
   570→                else
   571→                {
   572→                    if (run >= minLen)
   573→                    {
   574→                        return i + 1;
   575→                    }
   576→
   577→                    run = 0;
   578→                }
   579→            }
   580→
   581→            if (run >= minLen)
   582→            {
   583→                return 0;
   584→            }
   585→
   586→            return -1;
   587→        }
   588→
   589→        private static int IndexOf(byte[] buf, int start, int len, byte val)
   590→        {
   591→            int end = start + len;
   592→
   593→            for (int i = start; i < end; i++)
   594→            {
   595→                if (buf[i] == val)
   596→                {
   597→                    return i;
   598→                }
   599→            }
   600→
   601→            return -1;
   602→        }
