   604→        // ===== 송신 =====
   605→        private void SendRead(string addr, string countHex)
   606→        {
   607→            byte[] a = Encoding.ASCII.GetBytes(addr);
   608→            byte[] c = Encoding.ASCII.GetBytes(countHex);
   609→
   610→            byte[] pkt = new byte[1 + 3 + 2 + 2 + a.Length + c.Length + 1];
   611→            int p = 0;
   612→
   613→            pkt[p++] = ENQ;
   614→            pkt[p++] = (byte)'0';
   615→            pkt[p++] = (byte)'0';
   616→            pkt[p++] = (byte)'R';
   617→            pkt[p++] = (byte)'S';
   618→            pkt[p++] = (byte)'B';
   619→            pkt[p++] = (byte)'0';
   620→            pkt[p++] = (byte)'7';
   621→            Buffer.BlockCopy(a, 0, pkt, p, a.Length);
   622→            p += a.Length;
   623→            Buffer.BlockCopy(c, 0, pkt, p, c.Length);
   624→            p += c.Length;
   625→            pkt[p++] = EOT;
   626→
   627→            lock (_txLock)
   628→            {
   629→                _port.Write(pkt, 0, pkt.Length);
   630→            }
   631→
   632→            LogTx("TX R " + addr);
   633→        }
   634→
   635→        private void SendWrite(string addr, int outOffset)
   636→        {
   637→            // 스냅샷으로 페이로드 생성(경쟁조건 방지)
   638→            bool[] snap = new bool[32];
   639→
   640→            lock (_outLock)
   641→            {
   642→                Array.Copy(_out, outOffset, snap, 0, 32);
   643→            }
   644→
   645→            byte[] payload = new byte[128];
   646→            int k = 0;
   647→
   648→            for (int i = 0; i < 32; i++)
   649→            {
   650→                bool on = snap[i];
   651→                payload[k++] = (byte)'0';
   652→                payload[k++] = (byte)'0';
   653→                payload[k++] = (byte)'0';
   654→                payload[k++] = on ? (byte)'1' : (byte)'0';
   655→            }
   656→
   657→            byte[] a = Encoding.ASCII.GetBytes(addr);
   658→            byte[] c = Encoding.ASCII.GetBytes(CNT_32);
   659→
   660→            byte[] pkt = new byte[1 + 3 + 2 + 2 + a.Length + c.Length + payload.Length + 1];
   661→            int p = 0;
   662→
   663→            pkt[p++] = ENQ;
   664→            pkt[p++] = (byte)'0';
   665→            pkt[p++] = (byte)'0';
   666→            pkt[p++] = (byte)'W';
   667→            pkt[p++] = (byte)'S';
   668→            pkt[p++] = (byte)'B';
   669→            pkt[p++] = (byte)'0';
   670→            pkt[p++] = (byte)'7';
   671→            Buffer.BlockCopy(a, 0, pkt, p, a.Length);
   672→            p += a.Length;
   673→            Buffer.BlockCopy(c, 0, pkt, p, c.Length);
   674→            p += c.Length;
   675→            Buffer.BlockCopy(payload, 0, pkt, p, payload.Length);
   676→            p += payload.Length;
   677→            pkt[p++] = EOT;
   678→
   679→            lock (_txLock)
   680→            {
   681→                _port.Write(pkt, 0, pkt.Length);
   682→            }
   683→
   684→            LogTx("TX W " + addr);
   685→        }
