    13→    {
    14→        /// <summary>
    15→        /// SQL Server Table_Main 테이블에 필요한 컬럼이 있는지 확인하고 없으면 추가
    16→        /// 컬럼명 앞에 OP_NOISETEST_ 접두사 추가
    17→        /// </summary>
    18→        // 버전 번호: requiredColumns 변경 시 증가시킬 것
    19→        private const string SQL_STRUCTURE_VERSION = "2";
