   253→        /// <summary>
   254→        /// 테이블의 컬럼 목록을 가져옴
   255→        /// </summary>
   256→        private static Dictionary<string, string> GetTableColumns(OleDbConnection conn, string tableName)
   257→        {
   258→            var columns = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
   259→
   260→            try
   261→            {
   262→                // SQL Server에서 컬럼 정보 조회
   263→                var schema = conn.GetOleDbSchemaTable(OleDbSchemaGuid.Columns, 
   264→                    new object[] { null, null, tableName, null });
   265→
   266→                if (schema != null)
   267→                {
   268→                    foreach (System.Data.DataRow row in schema.Rows)
   269→                    {
   270→                        string columnName = row["COLUMN_NAME"].ToString();
   271→                        string dataType = row["DATA_TYPE"].ToString();
   272→                        columns[columnName] = dataType;
   273→                    }
   274→                }
   275→            }
   276→            catch (Exception ex)
   277→            {
   278→                // 테이블이 없을 수 있음
   279→                throw new Exception($"테이블 {tableName} 조회 실패: {ex.Message}");
   280→            }
   281→
   282→            return columns;
   283→        }
