   128→    // --- 100ms 폴링 스텝 머신 ---
   129→    private void OnTick(object sender, EventArgs e)
   130→    {
   131→        try
   132→        {
   133→            if (!_port.IsOpen) return;
   134→
   135→            // 1) Open 직후 1회만 *ADR 1 송신
   136→            if (_adrPending && !_adrSent)
   137→            {
   138→                // 간단한 지연 처리 (타이머 간격 기준 누적)
   139→                _adrDelayRemainMs -= _timer.Interval;
   140→                if (_adrDelayRemainMs <= 0)
   141→                {
   142→                    WriteLineSafe("*ADR 1");
   143→                    _adrSent = true;
   144→                    _adrPending = false;
   145→                    Log("[INIT] *ADR 1 sent once after open.");
   146→                }
   147→                // ADR 처리 중에는 본 루프 진행 안 하고 다음 틱에서 계측 시작
   148→                return;
   149→            }
   150→
   151→            // 2) 응답 대기 상태(1, 3)에서 타임아웃 체크
   152→            if ((_step == 1 || _step == 3) && _awaitSw.IsRunning)
   153→            {
   154→                if (_awaitSw.ElapsedMilliseconds > ResponseTimeoutMs)
   155→                {
   156→                    ResetState("No response within " + ResponseTimeoutMs + " ms (step=" + _step + ")");
   157→                    return;
   158→                }
   159→            }
   160→
   161→            // 3) 측정/설정 스텝
   162→            switch (_step)
   163→            {
   164→                case 0:
   165→                    if (Mode == MeasureMode.ModeA)
   166→                    {
   167→                        WriteLineSafe("MEAS:CURR?");
   168→                        _step = 3;
   169→                        _awaitSw.Restart();
   170→                    }
   171→                    else
   172→                    {
   173→                        WriteLineSafe("MEAS:VOLT?");
   174→                        _step = 1;
   175→                        _awaitSw.Restart();
   176→                    }
   177→                    break;
   178→
   179→                case 1: // VOLT 응답 대기
   180→                    break;
   181→
   182→                case 2: // CURR? 요청
   183→                    WriteLineSafe("MEAS:CURR?");
   184→                    _step = 3;
   185→                    _awaitSw.Restart();
   186→                    break;
   187→
   188→                case 3: // CURR 응답 대기
   189→                    break;
   190→
   191→                case 4: // 전압 설정
   192→                    WriteLineSafe("SOUR:VOLT " + TargetVolt.ToString("0.###", CultureInfo.InvariantCulture));
   193→                    _step = 0;
   194→                    _awaitSw.Reset();
   195→                    break;
   196→            }
   197→        }
   198→        catch (Exception ex)
   199→        {
   200→            Log("[ERR] Tick: " + ex.Message);
   201→        }
   202→    }
   203→
   204→    // --- 수신 처리 (백그라운드 스레드) ---
   205→    private void OnDataReceived(object sender, SerialDataReceivedEventArgs e)
   206→    {
   207→        try
   208→        {
   209→            string chunk = _port.ReadExisting();
   210→            if (string.IsNullOrEmpty(chunk)) return;
   211→
   212→            lock (_lock)
   213→            {
   214→                _rx.Append(chunk);
   215→
   216→                // CR 기준 라인 파싱
   217→                while (true)
   218→                {
   219→                    int cr = _rx.ToString().IndexOf('\r');
   220→                    if (cr < 0) break;
   221→
   222→                    string line = _rx.ToString(0, cr);
   223→                    _rx.Remove(0, cr + 1);
   224→
   225→                    HandleLine(line.Trim());
   226→                }
   227→            }
   228→        }
   229→        catch (Exception ex)
   230→        {
   231→            Log("[ERR] RX: " + ex.Message);
   232→        }
   233→    }
   234→
   235→    private void HandleLine(string line)
   236→    {
   237→        if (string.IsNullOrWhiteSpace(line)) return;
   238→
   239→        if (_step == 1) // VOLT 응답
   240→        {
   241→            double v;
   242→            if (TryParseDouble(line, out v))
   243→            {
   244→                ValueVolt = v;
   245→                _awaitSw.Reset();
   246→                _step = 2; // 전류 요청 단계
   247→            }
   248→            return;
   249→        }
   250→
   251→        if (_step == 3) // CURR 응답
   252→        {
   253→            double a;
   254→            if (TryParseDouble(line, out a))
   255→            {
   256→                ValueCurr = a;
   257→                _awaitSw.Reset();
   258→
   259→                if (Mode == MeasureMode.ModeA)
   260→                    _step = 0; // 바로 반복
   261→                else
   262→                    _step = 4; // 전압 설정
   263→            }
   264→            return;
   265→        }
   266→    }
   267→
   268→    private static bool TryParseDouble(string s, out double value)
   269→    {
   270→        return double.TryParse(s, NumberStyles.Float, CultureInfo.InvariantCulture, out value);
   271→    }
   272→
   273→    private void WriteLineSafe(string cmd)
   274→    {
   275→        if (!_port.IsOpen) return;
   276→        _port.Write(cmd);
   277→        _port.Write(_port.NewLine);
   278→    }
   279→
   280→    private void ResetState(string reason)
   281→    {
   282→        try
   283→        {
   284→            _awaitSw.Reset();
   285→            _step = 0;
   286→            lock (_lock) { _rx.Clear(); }
   287→            try { _port.DiscardInBuffer(); } catch { }
   288→            Log("[TIMEOUT] " + reason + ". State reset (step=0).");
   289→        }
   290→        catch (Exception ex)
   291→        {
   292→            Log("[ERR] ResetState: " + ex.Message);
   293→        }
   294→    }
   295→
   296→    // --- 유틸: 외부에서 재연결 시 ADR 재송신을 원할 때 호출 ---
   297→    public void RequestAdrResendOnNextTick()
   298→    {
   299→        if (_port.IsOpen)
   300→        {
   301→            _adrSent = false;
   302→            _adrPending = true;
   303→            _adrDelayRemainMs = PostOpenAdrDelayMs;
   304→        }
   305→    }
   306→}
