   105→    // Hioki-3544 레인지를 3옴으로 설정
   106→    private void SetRange3Ohm()
   107→    {
   108→        try
   109→        {
   110→            // 자동 레인지 비활성화
   111→            _port.Write(":SENS:RES:RANG:AUTO OFF\r\n");
   112→            Thread.Sleep(50); // 명령 처리 대기
   113→            
   114→            // 3옴 레인지로 설정
   115→            _port.Write(":SENS:RES:RANG 3\r\n");
   116→            Thread.Sleep(50); // 명령 처리 대기
   117→        }
