    95→    /// <summary>
    96→    /// 각도 측정 요청 (필요시)
    97→    /// WitMotion은 자동으로 데이터를 전송하므로 일반적으로 필요 없음
    98→    /// </summary>
    99→    public void RequestAngle()
   100→    {
   101→        // WitMotion HWT101CT는 자동으로 데이터를 전송하므로 명령 불필요
   102→    }
   103→
   104→
   105→    private void ReadLoop()
   106→    {
   107→        var buffer = new byte[1024];
   108→        var packetBuffer = new System.Collections.Generic.List<byte>();
   109→
   110→        try
   111→        {
   112→            while (_running && _port.IsOpen)
   113→            {
   114→                try
   115→                {
   116→                    int bytesRead = _port.Read(buffer, 0, buffer.Length);
   117→                    if (bytesRead > 0)
   118→                    {
   119→                        // 수신된 바이트를 패킷 버퍼에 추가
   120→                        for (int i = 0; i < bytesRead; i++)
   121→                        {
   122→                            packetBuffer.Add(buffer[i]);
   123→                        }
   124→
   125→                        // 패킷 처리
   126→                        ProcessPackets(packetBuffer);
   127→                    }
   128→                }
   129→                catch (TimeoutException)
   130→                {
   131→                    // 타임아웃은 정상 (데이터 없음)
   132→                    Thread.Sleep(10);
   133→                }
   134→                catch (Exception ex)
   135→                {
   136→                    Log($"ReadLoop 오류: {ex.Message}");
   137→                    Thread.Sleep(100);
   138→                }
   139→            }
   140→        }
   141→        catch (Exception ex)
   142→        {
   143→            Log($"ReadLoop 종료: {ex.Message}");
   144→        }
   145→    }
   146→
   147→    /// <summary>
   148→    /// 바이너리 패킷 처리
   149→    /// </summary>
   150→    private void ProcessPackets(System.Collections.Generic.List<byte> buffer)
   151→    {
   152→        while (buffer.Count >= ANGLE_PACKET_LENGTH)
   153→        {
   154→            // 헤더 찾기
   155→            int headerIndex = -1;
   156→            for (int i = 0; i <= buffer.Count - ANGLE_PACKET_LENGTH; i++)
   157→            {
   158→                if (buffer[i] == HEADER && buffer.Count - i >= ANGLE_PACKET_LENGTH)
   159→                {
   160→                    headerIndex = i;
   161→                    break;
   162→                }
   163→            }
   164→
   165→            if (headerIndex == -1)
   166→            {
   167→                // 헤더를 찾지 못하면 버퍼 정리 (최대 10바이트만 유지)
   168→                if (buffer.Count > 10)
   169→                {
   170→                    buffer.RemoveRange(0, buffer.Count - 10);
   171→                }
   172→                break;
   173→            }
   174→
   175→            // 헤더 이전 데이터 제거
   176→            if (headerIndex > 0)
   177→            {
   178→                buffer.RemoveRange(0, headerIndex);
   179→            }
   180→
   181→            // 패킷 길이 확인
   182→            if (buffer.Count < ANGLE_PACKET_LENGTH)
   183→            {
   184→                break;
   185→            }
   186→
   187→            // 각도 데이터 패킷 확인 (0x55 0x53)
   188→            if (buffer[0] == HEADER && buffer[1] == CMD_ANGLE)
   189→            {
   190→                // 패킷 추출
   191→                byte[] packet = new byte[ANGLE_PACKET_LENGTH];
   192→                for (int i = 0; i < ANGLE_PACKET_LENGTH; i++)
   193→                {
   194→                    packet[i] = buffer[i];
   195→                }
   196→
   197→                // 로우 데이터 로깅
   198→                if (LogRawData && EnableLog)
   199→                {
   200→                    string hexStr = BitConverter.ToString(packet).Replace("-", " ");
   201→                    Log($"RAW: {hexStr}");
   202→                }
   203→
   204→                // 각도 데이터 파싱
   205→                ParseAnglePacket(packet);
   206→
   207→                // 처리된 패킷 제거
   208→                buffer.RemoveRange(0, ANGLE_PACKET_LENGTH);
   209→            }
   210→            else
   211→            {
   212→                // 다른 타입의 패킷이면 헤더만 제거하고 계속
   213→                buffer.RemoveAt(0);
   214→            }
   215→        }
   216→    }
   217→
   218→    /// <summary>
   219→    /// 각도 패킷 파싱 (0x55 0x53 [X_L] [X_H] [Y_L] [Y_H] [Z_L] [Z_H] [Checksum] ...)
   220→    /// 각 값은 signed 16-bit integer, 32768로 나누면 각도(도)
   221→    /// </summary>
   222→    private void ParseAnglePacket(byte[] packet)
   223→    {
   224→        if (packet.Length < 8 || packet[0] != HEADER || packet[1] != CMD_ANGLE)
   225→        {
   226→            return;
   227→        }
   228→
   229→        try
   230→        {
   231→            // X축 - Low, High 바이트
   232→            short xRaw = (short)(packet[2] | (packet[3] << 8));
   233→            double x = xRaw / 32768.0 * 180.0;
   234→
   235→            // Y축 - Low, High 바이트
   236→            short yRaw = (short)(packet[4] | (packet[5] << 8));
   237→            double y = yRaw / 32768.0 * 180.0;
   238→
   239→            // Z축 - Low, High 바이트
   240→            short zRaw = (short)(packet[6] | (packet[7] << 8));
   241→            double z = zRaw / 32768.0 * 180.0;
   242→
   243→            // 값 업데이트
   244→            AngleX = x;
   245→            AngleY = y;
   246→            AngleZ = z;
   247→
   248→            // 이벤트 발생
   249→            AngleReceived?.Invoke(this, new AngleReceivedEventArgs(x, y, z));
   250→
   251→            if (EnableLog)
   252→            {
   253→                Log($"각도 X:{x:F3}° Y:{y:F3}° Z:{z:F3}°");
   254→            }
   255→        }
   256→        catch (Exception ex)
   257→        {
   258→            Log($"각도 패킷 파싱 오류: {ex.Message}");
   259→        }
   260→    }
   261→
   262→
   263→    private void Log(string message)
   264→    {
   265→        if (EnableLog && _log != null)
   266→        {
   267→            _log($"[SerialAngle] {message}");
   268→        }
   269→    }
