   211→        private void EnsureLoaded()
   212→        {
   213→            lock (_lock)
   214→            {
   215→                if (_cachedTable != null && _cachedTable.Rows.Count > 0)
   216→                    return;
   217→
   218→                LoadFromDatabase();
   219→            }
