   222→        private void LoadFromDatabase()
   223→        {
   224→            try
   225→            {
   226→                // 연결 문자열에서 파일 경로 추출
   227→                var dbPath = ExtractDbPath(_connectionString);
   228→                if (!File.Exists(dbPath))
   229→                {
   230→                    _logger?.Warning($"ACCDB 파일이 없음: {dbPath}");
   231→                    _cachedTable = new DataTable();
   232→                    return;
   233→                }
   234→
   235→                using (var conn = new OleDbConnection(_connectionString))
   236→                {
   237→                    conn.Open();
   238→
   239→                    string sql = @"SELECT ID, TestID, BarcodeID, PartNo, PartName, CarType, 
   240→                                          Target_SW_Ver, Target_HW_Ver, ScanTarget, ControlType 
   241→                                   FROM Table_Part 
   242→                                   ORDER BY PartNo ASC";
   243→
   244→                    using (var adapter = new OleDbDataAdapter(sql, conn))
   245→                    {
   246→                        adapter.MissingSchemaAction = MissingSchemaAction.Add;
   247→                        _cachedTable = new DataTable();
   248→                        adapter.Fill(_cachedTable);
   249→                    }
   250→                }
   251→
   252→                _logger?.Info($"[DB] Table_Part loaded. rows={_cachedTable.Rows.Count}");
   253→            }
   254→            catch (Exception ex)
   255→            {
   256→                _logger?.Error($"부품 데이터 로드 실패: {ex.Message}", ex);
   257→                _cachedTable = new DataTable();
   258→            }
   259→        }
   260→
   261→        private string ExtractDbPath(string connectionString)
   262→        {
   263→            // "Data Source=..." 형식에서 경로 추출
   264→            const string prefix = "Data Source=";
   265→            int index = connectionString.IndexOf(prefix);
   266→            if (index >= 0)
   267→            {
   268→                return connectionString.Substring(index + prefix.Length).Trim();
   269→            }
   270→            return string.Empty;
   271→        }
   272→    }
   273→}
